-- 아이스크림 프로 홈페이지 Supabase 스키마 + 초기 데이터
-- Supabase 대시보드 > SQL Editor 에 붙여넣고 RUN 하세요.

-- 1) 테이블 ---------------------------------------------------
create table if not exists categories (
  key   text primary key,
  label text not null,
  icon  text,
  sort  int default 0
);

create table if not exists courses (
  id            bigint primary key,
  title         text not null,
  credit        text,
  category      text references categories(key),
  category_name text,
  price         bigint default 0,
  status        text default 'open',
  url           text
);

create table if not exists inquiries (
  id         bigint generated by default as identity primary key,
  org        text,
  region     text,
  phone      text,
  message    text,
  status     text default 'new',
  created_at timestamptz default now()
);
-- 2) 보안(RLS): 카탈로그는 공개 읽기, 문의는 등록만 허용 ----------
alter table categories enable row level security;
alter table courses    enable row level security;
alter table inquiries  enable row level security;

create policy "read categories" on categories for select to anon using (true);
create policy "read courses"    on courses    for select to anon using (true);
create policy "insert inquiry"  on inquiries  for insert to anon with check (true);
